// Get all the unit links from the paid section
const links = document.querySelectorAll('article a[href*="note.com/tak661/n/"]');
const unitLinks = [];
const seen = new Set();
links.forEach(a => {
  const text = a.textContent.trim();
  const href = a.href;
  if (text && href && !seen.has(href) && text !== '統計検定®準１級講座【note＋YouTube】') {
    seen.add(href);
    unitLinks.push({ name: text, url: href });
  }
});
JSON.stringify(unitLinks, null, 2);

